## 2. The minimal fix – always release (or use `pool.query`)

### Option A – Keep the explicit `connect()` but add `finally`

```javascript
// utils/db.js (single pool instance)
const { Pool } = require('pg');

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  // optional tuning
  max: 20,                  // keep same as before or bump after testing
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

module.exports = pool;
```

```javascript
// routes/users.js
const express = require('express');
const router = express.Router();
const pool = require('../utils/db');

router.get('/api/users/:id', async (req, res, next) => {
  let client;
  try {
    client = await pool.connect();                // acquire
    const { rows } = await client.query(
      'SELECT * FROM users WHERE id = $1',
      [req.params.id]
    );
    if (rows.length === 0) {
      return res.status(404).json({ error: 'User not found' });
    }
    res.json(rows[0]);
  } catch (err) {
    // Log and forward to Express error handler
    console.error('DB error:', err);
    next(err);   // will become 502/500 depending on your error middleware
  } finally {
    // <-- ALWAYS release, even on error or early return
    if (client) client.release();
  }
});

module.exports = router;
```

### Option B – Let the pool handle acquire/release for you

`pg`’s `pool.query()` is a thin wrapper that does exactly the same thing but guarantees the client is returned to the pool even when an exception is thrown.

```javascript
router.get('/api/users/:id', async (req, res, next) => {
  try {
    const { rows } = await pool.query(
      'SELECT * FROM users WHERE id = $1',
      [req.params.id]
    );
    if (!rows[0]) return res.status(404).json({ error: 'User not found' });
    res.json(rows[0]);
  } catch (err) {
    console.error('DB error:', err);
    next(err);
  }
});
```

**Why Option B is preferred:**  
* No manual `client.release()` to forget.  
* Fewer lines of code → less chance of a leak.  
* Still gives you the full power of the pool (connection reuse, queuing).

